B.Ny=new A.al("The fire suppression system discharged successfully into the engine nacelle.","Yang\u0131n bast\u0131rma sistemi motor kovan\u0131na ba\u015far\u0131yla de\u015farj edildi.","fire suppression system")
B.Mz=new A.al("All cabin crew must demonstrate the life vest donning procedure to passengers.","T\xfcm kabin ekibi yolculara can yele\u011fi giyinme prosed\xfcr\xfcn\xfc g\xf6stermelidir.","donning procedure")
