B.Nm=new A.al("The crew was forced to divert to Valencia after a hydraulic failure.","Ekip, hidrolik ar\u0131zas\u0131n\u0131n ard\u0131ndan Valencia'ya y\xf6n de\u011fi\u015ftirmek zorunda kald\u0131.","divert")
B.Mx=new A.al("Following the gear malfunction, the captain decided to abort the landing.","\u0130ni\u015f tak\u0131m\u0131 ar\u0131zas\u0131n\u0131n ard\u0131ndan kaptan ini\u015fi iptal etmeye karar verdi.","abort")
