B.RG=new A.J(B.am,"\u2708\ufe0f S\u0131nav \u0130pucu",'En yayg\u0131n METAR \xe7eviri hatalar\u0131:\n\u2022 **9999** = 10 km veya daha fazla g\xf6r\xfc\u015f (YANLI\u015e: "tam 9.999 metre")\n\u2022 **FEW030** = 3.000 ft\'te bulut (METAR bulut y\xfcksekli\u011finin sonuna iki s\u0131f\u0131r ekle)\n\u2022 **18/08** = s\u0131cakl\u0131k 18\xb0C, \xe7i\u011f noktas\u0131 8\xb0C (YANLI\u015e: "18\'den 8\'e")\n\u2022 **NOSIG** = \xf6n\xfcm\xfczdeki 2 saat i\xe7in \xf6nemli de\u011fi\u015fiklik beklenmiyor (YANLI\u015e: "sinyal yok")\n\u2022 R\xfczgar "35015KT" = 350\xb0\'DEN geliyor, h\u0131z 15 knot (y\xf6n, r\xfczgar\u0131n NEREDEN geldi\u011fini g\xf6sterir)',null,null,null)
