B.Uu=new A.J(B.S,"Neden standart ifadeler \xf6nemlidir","Kabin g\xfcvenlik anonslar\u0131 **d\xfczenleyici kurumlar taraf\u0131ndan onaylanm\u0131\u015f** sabit ifadeler i\xe7erir. IATA ve havayollar\u0131n\u0131n kendi prosed\xfcrleri, yolcular\u0131n her u\xe7u\u015fta ayn\u0131 mesaj\u0131 anlamas\u0131n\u0131 sa\u011flamak i\xe7in belirli kelimeler kullan\u0131r.\n\nBu kal\u0131plar\u0131 ezberlemek, bask\u0131 alt\u0131nda bile do\u011fru ve net ileti\u015fim kurman\u0131z\u0131 sa\u011flar.",null,null,null)
B.Uz=new A.J(B.A,"\ud83d\udccb Temel Anonslardaki Kal\u0131plar",'**Kalk\u0131\u015f \xf6ncesi:**\n\u2022 "Please ensure your seatbelt is fastened and your seat is in the upright position."\n\u2022 "All portable electronic devices must be switched off or set to flight mode."\n\u2022 "Please direct your attention to the cabin crew for the safety demonstration."\n\n**T\xfcrb\xfclans:**\n\u2022 "The captain has turned on the fasten seatbelt sign. Please return to your seats immediately."\n\n**\u0130ni\u015f:**\n\u2022 "Cabin crew, please prepare for landing."\n\u2022 "We are beginning our descent into [city]."\n\n**Anahtar fiiller:** *ensure, fasten, secure, remain, proceed, direct*',null,null,null)
B.Mr=new A.al("Ladies and gentlemen, please ensure all carry-on baggage is stowed in the overhead bins or under the seat in front of you.","Bayanlar ve baylar, l\xfctfen t\xfcm el bagajlar\u0131n\u0131z\u0131n \xfcstteki bagaj b\xf6lmelerinde veya \xf6n\xfcn\xfczdeki koltu\u011fun alt\u0131nda yerle\u015ftirildi\u011finden emin olun.","ensure \u2026 is stowed")
B.Nj=new A.al("We remind you that this is a non-smoking flight. Smoking is prohibited throughout the aircraft, including the lavatories.","Bu u\xe7u\u015fun sigara i\xe7ilmeyen bir u\xe7u\u015f oldu\u011funu hat\u0131rlat\u0131r\u0131z. Tuvaletler dahil olmak \xfczere u\xe7ak i\xe7inde sigara i\xe7mek yasakt\u0131r.","is prohibited")
B.MF=new A.al("In the event of a sudden loss of cabin pressure, oxygen masks will drop from above. Pull the mask towards you, place it over your nose and mouth, and breathe normally.","Kabin bas\u0131nc\u0131nda ani bir d\xfc\u015f\xfc\u015f olmas\u0131 durumunda, oksijen maskeleri yukar\u0131dan d\xfc\u015fecektir.","In the event of")
