B.Sl=new A.J(B.S,"CRM neden hayati \xf6nem ta\u015f\u0131r","**Crew Resource Management (CRM)**, kaza \xf6nlemede kritik bir fakt\xf6rd\xfcr. Ara\u015ft\u0131rmalar, u\xe7ak kazalar\u0131n\u0131n b\xfcy\xfck \xe7o\u011funlu\u011funun teknik ar\u0131zadan de\u011fil **ileti\u015fim ve ekip koordinasyonu** yetersizli\u011finden kaynakland\u0131\u011f\u0131n\u0131 g\xf6stermektedir.\n\nEtkili CRM dili \u015funlar\u0131 i\xe7erir: a\xe7\u0131k \xe7a\u011fr\u0131 y\xf6ntemi, challenge-response, sterile cockpit kural\u0131na uyum ve g\xfcvenlik endi\u015felerini iletebilme.",null,null,null)
B.TJ=new A.J(B.A,"\ud83d\udd04 CRM \u0130leti\u015fim Teknikleri",'**Closed-loop communication (kapal\u0131 d\xf6ng\xfc ileti\u015fim):**\n\u2022 G\xf6nderici mesaj\u0131 iletir\n\u2022 Al\u0131c\u0131 mesaj\u0131 tekrarlar\n\u2022 G\xf6nderici onaylar\n\n**Assertiveness (iddial\u0131 ileti\u015fim):**\n\u2022 "I am concerned about \u2026" \u2014 endi\u015feyi bildirme\n\u2022 "I recommend we \u2026" \u2014 \xf6neri\n\u2022 "I need to advise you that \u2026" \u2014 uyar\u0131\n\n**Sterile cockpit:**\n\u2022 "Sterile cockpit is now in effect" \u2014 u\xe7u\u015fun kritik fazlar\u0131nda\n\u2022 Yaln\u0131zca g\xfcvenlikle ilgili ileti\u015fim\n\n**Pre-flight briefing:**\n\u2022 "Today\'s senior cabin crew is \u2026"\n\u2022 "Our emergency equipment locations are \u2026"\n\u2022 "In the event of \u2026, our procedure is \u2026"',null,null,null)
