B.So=new A.J(B.S,"Resmi havac\u0131l\u0131k belgelerinin \xf6zel dil kal\u0131plar\u0131 vard\u0131r","Operasyon k\u0131lavuzlar\u0131, bak\u0131m k\u0131lavuzlar\u0131 (AMM) ve u\xe7u\u015fa elveri\u015flilik direktifleri, kesin hukuki ve teknik \xe7\u0131kar\u0131mlar i\xe7eren resmi \u0130ngilizce kullan\u0131r. Bu d\xfczeydeki \xe7eviri sorular\u0131, yaln\u0131zca kelimeleri de\u011fil, arkar\u0131ndaki **d\xfczenleyici amac\u0131** da anlamay\u0131 gerektirir.",null,null,null)
B.UA=new A.J(B.A,"\ud83d\udcd5 D\xfczenleyici Dil","**Shall** \u2014 mandatory requirement (legal obligation in ICAO documents)\n**Should** \u2014 recommended practice (not legally binding, but expected)\n**May** \u2014 permitted (optional)\n**Must** \u2014 mandatory (operational context, not formal ICAO legal text)\n\n**Compliance** \u2014 acting in accordance with a regulation\n**In accordance with (IAW)** \u2014 following specified requirements\n**Subject to** \u2014 conditional upon something\n**Notwithstanding** \u2014 despite; even though\n**Hereinafter** \u2014 from this point forward in the document",null,null,null)
B.Mm=new A.al("All maintenance shall be carried out by qualified personnel in accordance with the approved data.","T\xfcm bak\u0131m i\u015flemleri, onayl\u0131 veriye uygun olarak nitelikli personel taraf\u0131ndan yap\u0131lmal\u0131d\u0131r.","shall be carried out")
