B.MZ=new A.al("Under RVSM, vertical separation between FL290 and FL410 is reduced to 1,000 feet.","RVSM kapsam\u0131nda, FL290 ile FL410 aras\u0131ndaki dikey ay\u0131rma 1.000 fite indirilmi\u015ftir.","RVSM")
B.Ms=new A.al("The aircraft was dispatched on the MEL, with one hydraulic pump deferred.","U\xe7ak, bir hidrolik pompa ertelenmi\u015f olarak MEL'e g\xf6re hava arac\u0131 olarak g\xf6nderildi.","MEL")
