B.RV=new A.J(B.R,"Pratik Sorular",'Read the following AD extract:\n\n"This Airworthiness Directive is applicable to all Airbus A320-200 aircraft, serial numbers 3001 through 5500. The unsafe condition is potential fatigue cracking of the forward fuselage frame. Required action: Perform a detailed visual inspection of the forward fuselage frame assembly. Compliance time: Within 100 flight cycles after the effective date of this AD. Repetitive inspection interval: Every 500 flight cycles thereafter. Terminating action: Replacement of the frame assembly with Part Number A320-FR-9902 permanently terminates the repetitive inspection requirement."',null,null,B.Zp)
B.W_=s([B.TM,B.Te,B.UP,B.TX,B.Ul,B.RV],t.q)
B.n4=new A.bM("reading_6","U\xe7u\u015fa Elveri\u015flilik Direktifleri","Zorunlu g\xfcvenlik bildirimlerini okuma ve yorumlama","reading","\ud83d\udcdc",B.W_)
B.RJ=new A.J(B.S,"\u0130leri d\xfczey tamamlama tam ba\u011flam anlay\u0131\u015f\u0131 gerektirir","\u0130leri d\xfczeyde c\xfcmle tamamlama sorular\u0131, birden fazla se\xe7ene\u011fin dilbilgisel olarak do\u011fru g\xf6r\xfcnebildi\u011fi karma\u015f\u0131k teknik c\xfcmleler i\xe7erir. Do\u011fru cevap hem dilbilgisi **hem de** havac\u0131l\u0131k teknik bilgisi gerektirmektedir.",null,null,null)
B.T1=new A.J(B.A,"\u2699\ufe0f Teknik \xd6bek Kal\u0131plar\u0131",'Havac\u0131l\u0131k teknik yaz\u0131m\u0131, her zaman birlikte kullan\u0131lan sabit \xf6bekler i\xe7erir:\n\n\u2022 perform/carry out/conduct (**a maintenance check**) \u2014 "make" veya "do" de\u011fil\n\u2022 comply with (**regulations**) \u2014 "follow to" de\u011fil\n\u2022 in accordance with (**AMM/CMM**) \u2014 standart ifade\n\u2022 prior to/following (**departure**) \u2014 resmi zaman ifadeleri\n\u2022 serviceability of (**equipment**) \u2014 uu\xe7u\u015fa elveri\u015flilik terimi\n\u2022 within the limits (**specified in**) \u2014 uyumluluk dili',null,null,null)
B.SG=new A.J(B.A,"\ud83d\udcd0 Kesinlik Dili","Havac\u0131l\u0131k \u0130ngilizcesi zarafet yerine **kesinli\u011fe** de\u011fer verir. Kelimeler birbirinin yerine kullan\u0131lamaz:\n\u2022 **inspect** = g\xf6rsel inceleme | **test** = i\u015flevsel do\u011frulama | **check** = durumu onaylama\n\u2022 **fault** = belirli ar\u0131za | **failure** = tam fonksiyon kayb\u0131 | **malfunction** = k\u0131smi/aral\u0131kl\u0131 ar\u0131za\n\u2022 **serviceable** = kullan\u0131ma uygun | **unserviceable** = kullan\u0131ma uygun de\u011fil (teknik terim)\n\u2022 **advise** = bildir/tavsiye et | **instruct** = zorunlu y\xf6n ver",null,null,null)
B.Nf=new A.al("All repairs must be carried out __________ the Aircraft Maintenance Manual.","T\xfcm onar\u0131mlar U\xe7ak Bak\u0131m El Kitab\u0131na uygun olarak yap\u0131lmal\u0131d\u0131r.","in accordance with")
B.Na=new A.al("The component was declared __________ after a detailed visual inspection.","Par\xe7a, ayr\u0131nt\u0131l\u0131 g\xf6rsel incelemenin ard\u0131ndan kullan\u0131lamaz ilan edildi.","unserviceable")
